jQuery(function($){'use strict';const VAT_FIELD=place_order_data.vatField;const BUTTON_SELECTOR=place_order_data.buttonSelector;const BUTTON_WRAPPER_CLASS='alg-wc-eu-vat-checkout-button-wrapper';const BUTTON_WRAPPER_SELECTOR='.'+BUTTON_WRAPPER_CLASS;const OVERLAY_CLASS='alg-wc-eu-vat-checkout-button-overlay';const OVERLAY_SELECTOR='.'+OVERLAY_CLASS;const $checkoutForm=$('form.checkout');const $vatField=$(`#${VAT_FIELD}`);const $vatFieldBlock=$(`#contact-alg_eu_vat-${VAT_FIELD}`);let yn_status=false;let observer=null;let debounceTimer=null;const isBlockCheckout=document.querySelector('.wc-block-checkout')!==null;const algVatConfirmModal={init(){if(isBlockCheckout){this.handleBlocksPlaceOrderClick()}else{this.handleCheckoutPlaceOrderClick()}this.handleOverlayClicks();if(BUTTON_SELECTOR!==''){if(isBlockCheckout){this.addOverlaysBlockCheckout()}else{this.addOverlays();$(document.body).on('updated_checkout',()=>{this.addOverlays()})}}},needsVat(){const classic=$vatField.is(':visible')&&$vatField.val()==='';const block=$vatFieldBlock.is(':visible')&&$vatFieldBlock.val()==='';return classic||block},handleCheckoutPlaceOrderClick(){$checkoutForm.on('checkout_place_order',function(){if(!algVatConfirmModal.needsVat()){return}confirmo.init({yesBg:place_order_data.yesBg,noBg:place_order_data.noBg,leftText:place_order_data.yes_text,rightText:place_order_data.no_text,});confirmo.show({msg:place_order_data.confirmation_text,callback_yes:function(){yn_status=true;$('#place_order').click()},callback_no:function(){yn_status=false}});return yn_status})},handleBlocksPlaceOrderClick(){document.addEventListener('click',function(e){if(!algVatConfirmModal.needsVat()){return}const button=e.target.closest('.wc-block-components-checkout-place-order-button');if(!button){return}if(yn_status){yn_status=false;return}e.preventDefault();e.stopImmediatePropagation();confirmo.init({yesBg:place_order_data.yesBg,noBg:place_order_data.noBg,leftText:place_order_data.yes_text,rightText:place_order_data.no_text,});confirmo.show({msg:place_order_data.confirmation_text,callback_yes:function(){yn_status=true;button.click()},callback_no:function(){yn_status=false}})},true)},addOverlays(){$(BUTTON_SELECTOR).each(function(){const $button=$(this);if(!$button.length){return}if(!$button.parent(BUTTON_WRAPPER_SELECTOR).length){$button.wrap(`<div class="${BUTTON_WRAPPER_CLASS}"></div>`)}const $wrapper=$button.parent(BUTTON_WRAPPER_SELECTOR).css('position','relative');if($wrapper.find(OVERLAY_SELECTOR).length){return}$wrapper.append($('<span>').addClass(OVERLAY_CLASS).css({position:'absolute',top:0,left:0,width:'100%',height:'100%',zIndex:1999,cursor:'pointer',background:'transparent',}))})},handleOverlayClicks(){$(document.body).on('click',OVERLAY_SELECTOR,function(e){e.preventDefault();e.stopPropagation();const $overlay=$(e.currentTarget);if(!algVatConfirmModal.needsVat()){$overlay.remove();return}confirmo.init({yesBg:place_order_data.yesBg,noBg:place_order_data.noBg,leftText:place_order_data.yes_text,rightText:place_order_data.no_text,});confirmo.show({msg:place_order_data.confirmation_text,callback_yes:function(){yn_status=true;$overlay.remove()},callback_no:function(){yn_status=false}});return yn_status})},addOverlaysBlockCheckout(){if(observer){observer.disconnect()}observer=new MutationObserver(()=>{clearTimeout(debounceTimer);debounceTimer=setTimeout(()=>{this.addOverlays()},200)});observer.observe(document.body,{childList:true,subtree:true})}};$(document).ready(function(){algVatConfirmModal.init()})});